+import { ConfigParseError } from "./errors.ts";
+
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${kebabToCamelCase(key)}` : kebabToCamelCase(key);
+    if (isPlainObject(item)) {
+      Object.assign(result, flattenConfig(item, name));
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
+
+export function kebabToCamelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char: string) => char.toUpperCase());
+}
+
+export function parseJson(content: string, path: string): Record<string, unknown> {
+  try {
+    const value: unknown = JSON.parse(content);
+    if (!isPlainObject(value)) {
+      throw new Error("Configuration must contain an object.");
+    }
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+export function parseRc(content: string, path: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  try {
+    for (const line of content.split(/\\r?\
/)) {
+      const trimmed = line.trim();
+      if (!trimmed || trimmed.startsWith("#")) continue;
+      const index = trimmed.indexOf("=");
+      if (index === -1) throw new Error(`Invalid line: ${line}`);
+      const key = trimmed.slice(0, index).trim();
+      let value = trimmed.slice(index + 1).trim();
+      if (!key) throw new Error(`Invalid line: ${line}`);
+      if (value.startsWith('"')) {
+        if (!value.endsWith('"') || value.length === 1) {
+          throw new Error(`Unterminated quoted value: ${line}`);
+        }
+        value = value.slice(1, -1);
+      }
+      result[kebabToCamelCase(key)] = coerceRcValue(value);
+    }
+    return result;
+  } catch (error) {
+    throw error instanceof ConfigParseError ? error : new ConfigParseError(path, error);
+  }
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:[eE][-+]?\\d+)?$/.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+export function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null && !Array.isArray(value);
+}
