Deno.test("[command] - config - uses RC files and CLI/env precedence", async () => {
  await withConfigDir(async (path) => {
    await Deno.writeTextFile(
      `${path}/.apprc`,
      '# comment\nport=12\nlabel="hello world"\nenabled=false\n',
    );
    const cmd = new Command()
      .config({ name: "app", searchPaths: [path] })
      .env("PORT=<value:number>")
      .option("--port <port:number>")
      .option("--label <label>")
      .option("--enabled");
    Deno.env.set("PORT", "13");
    try {
      const result = await cmd.parse(["--port", "14"]);
      assertEquals(result.options, {
        port: 14,
        label: "hello world",
        enabled: false,
      });
    } finally {
      Deno.env.delete("PORT");
    }
  });
});

Deno.test("[command] - config - merges search paths with earlier paths taking precedence", async () => {
  await withConfigDir(async (first) => {
    await withConfigDir(async (second) => {
      await Deno.writeTextFile(
        `${first}/app.json`,
        '{"value":"first","first":true}',
      );
      await Deno.writeTextFile(
        `${second}/app.json`,
        '{"value":"second","second":true}',
      );
      const cmd = new Command()
        .config({
          name: "app",
          searchPaths: [first, second],
          mergeConfigs: true,
        })
        .option("--value <value>")
        .option("--first")
        .option("--second");
      assertEquals((await cmd.parse([])).options, {
        value: "first",
        first: true,
        second: true,
      });
    });
  });
});

Deno.test("[command] - config - reports parse and validation failures", async () => {
  await withConfigDir(async (path) => {
    await Deno.writeTextFile(`${path}/app.json`, "{");
    const invalidJson = new Command().throwErrors().config({
      name: "app",
      searchPaths: [path],
    });
    await assertRejects(() => invalidJson.parse([]), ConfigParseError);

    await Deno.writeTextFile(`${path}/app.json`, '{"port":"wrong"}');
    const invalidValue = new Command().throwErrors()
      .config({ name: "app", searchPaths: [path] })
      .option("--port <port:number>");
    try {
      await invalidValue.parse([]);
      assert(false);
    } catch (error) {
      assertInstanceOf(error, ConfigValidationError);
    }
  });
});

